import type { Metadata } from "next";
import Link from "next/link";
import { JsonLd } from "@/components/json-ld";
import { LOCATION_PAGES, SERVICES, SERVICE_ORDER, getStates, type ServiceSlug } from "@/lib/restoration-data";
import {
  EMERGENCY_PHONE_DISPLAY,
  EMERGENCY_PHONE_E164,
  SITE_NAME,
  absoluteUrl,
  serviceLocationKeyword,
} from "@/lib/seo";

const primaryService = SERVICES["water-damage"];
const featuredLocations = LOCATION_PAGES.slice(0, 8);
const HOMEPAGE_STATE_LIMIT = 12;
const HOMEPAGE_CITIES_PER_STATE = 12;

export const metadata: Metadata = {
  title: "Emergency Restoration Services Across Canada",
  description:
    "Call now for 24/7 emergency restoration services across Canadian cities. Fast dispatch for water damage, fire damage, mold remediation, and hazmat cleanup.",
  alternates: {
    canonical: "/",
  },
  openGraph: {
    title: `${SITE_NAME} | Emergency Restoration Services Across Canada`,
    description:
      "Emergency-first restoration with direct phone intake, documented scopes, and city-specific service pages.",
    url: absoluteUrl("/"),
    type: "website",
    siteName: SITE_NAME,
  },
  twitter: {
    card: "summary_large_image",
    title: `${SITE_NAME} | Emergency Restoration Services Across Canada`,
    description: "Call now for 24/7 dispatch across Canadian cities.",
  },
  keywords: [
    "emergency restoration canada",
    ...featuredLocations.map((location) => serviceLocationKeyword(primaryService.name, location.cityName)),
  ],
};

export default function Home() {
  const states = getStates().slice(0, HOMEPAGE_STATE_LIMIT);
  const stateToCities = new Map<string, (typeof LOCATION_PAGES)[number][]>();
  for (const location of LOCATION_PAGES) {
    const current = stateToCities.get(location.stateSlug);
    if (current) {
      current.push(location);
    } else {
      stateToCities.set(location.stateSlug, [location]);
    }
  }

  const organizationSchema = {
    "@context": "https://schema.org",
    "@type": "Organization",
    name: SITE_NAME,
    url: absoluteUrl("/"),
    contactPoint: [
      {
        "@type": "ContactPoint",
        telephone: EMERGENCY_PHONE_E164,
        contactType: "emergency customer service",
        areaServed: "CA",
        availableLanguage: ["en"],
      },
    ],
  };

  const websiteSchema = {
    "@context": "https://schema.org",
    "@type": "WebSite",
    name: SITE_NAME,
    url: absoluteUrl("/"),
    potentialAction: {
      "@type": "SearchAction",
      target: `${absoluteUrl("/")}?q={search_term_string}`,
      "query-input": "required name=search_term_string",
    },
  };

  const serviceListSchema = {
    "@context": "https://schema.org",
    "@type": "ItemList",
    name: "Emergency Restoration Service Hubs",
    itemListElement: SERVICE_ORDER.map((serviceSlug, index) => {
      const service = SERVICES[serviceSlug];
      return {
        "@type": "ListItem",
        position: index + 1,
        name: service.name,
        url: absoluteUrl(`/services/${service.slug}`),
      };
    }),
  };

  return (
    <div className="iris-shell">
      <JsonLd data={organizationSchema} />
      <JsonLd data={websiteSchema} />
      <JsonLd data={serviceListSchema} />

      <main>
        <section className="iris-hero iris-section">
          <div className="iris-container grid gap-10 md:grid-cols-[1.15fr_0.85fr] md:items-center">
            <div>
              <p className="iris-hero-kicker">Emergency Response Network</p>
              <h1 className="iris-hero-title">
                {SITE_NAME}
                <span>Service + Location SEO Structure</span>
              </h1>
              <p className="iris-hero-lead">
                Call {EMERGENCY_PHONE_DISPLAY} for immediate dispatch. Every route is structured for local intent, like
                {" "}
                <strong>{serviceLocationKeyword(primaryService.name, "Ottawa")}</strong>, so users and AI search can
                extract action-ready service pages quickly.
              </p>
              <div className="iris-actions">
                <a href={`tel:${EMERGENCY_PHONE_DISPLAY.replace(/[^0-9]/g, "")}`} className="iris-btn iris-btn-primary">
                  Call {EMERGENCY_PHONE_DISPLAY}
                </a>
                <Link href="/services" className="iris-btn iris-btn-secondary">
                  Explore Service Hubs
                </Link>
              </div>
            </div>

            <div className="iris-card iris-card-pad bg-white/95">
              <h2 className="text-xl font-bold text-[#0d2d44]">Extractable City Keywords</h2>
              <ul className="mt-4 grid gap-2 sm:grid-cols-2">
                {LOCATION_PAGES.slice(0, 10).map((location) => (
                  <li key={`${location.stateSlug}-${location.citySlug}`}>
                    <Link
                      href={`/${location.stateSlug}/${location.citySlug}/water-damage`}
                      className="block rounded-xl border border-[#dbe2ea] bg-[#f8fbff] px-3 py-2 text-sm font-medium text-[#163147] transition hover:border-[#1e4a63] hover:bg-white"
                    >
                      {serviceLocationKeyword(primaryService.name, location.cityName)}
                    </Link>
                  </li>
                ))}
              </ul>
            </div>
          </div>
        </section>

        <section className="iris-section">
          <div className="iris-container">
            <div className="iris-card iris-card-pad">
              <h2 className="iris-title text-2xl">Quick Answer For AI Search</h2>
              <p className="iris-subtitle">
                <strong>What should a property owner do first after damage?</strong> Call immediately, isolate hazards,
                and start professional mitigation before secondary loss escalates.
              </p>
            </div>
          </div>
        </section>

        <section className="iris-section pt-0">
          <div className="iris-container">
            <div className="mb-7 flex flex-wrap items-end justify-between gap-4">
              <div>
                <h2 className="iris-title">Service Hubs</h2>
                <p className="iris-subtitle">Structured pages with definitions, process steps, and FAQs.</p>
              </div>
              <Link href="/services" className="iris-btn iris-btn-dark">
                View All Services
              </Link>
            </div>

            <div className="grid gap-5 md:grid-cols-2 xl:grid-cols-4">
              {SERVICE_ORDER.map((serviceSlug, idx) => {
                const service = SERVICES[serviceSlug as ServiceSlug];
                const gradientByIndex = [
                  "from-[#0d2d44]/10",
                  "from-[#ffd700]/18",
                  "from-[#00b4d8]/16",
                  "from-[#1e4a63]/12",
                ];

                return (
                  <Link
                    key={service.slug}
                    href={`/services/${service.slug}`}
                    className="iris-card relative overflow-hidden p-5"
                  >
                    <div
                      className={`pointer-events-none absolute -right-8 -top-8 h-24 w-24 rounded-full bg-gradient-to-br ${gradientByIndex[idx]} to-transparent blur-xl`}
                    />
                    <p className="text-xs font-bold uppercase tracking-[0.18em] text-[#1e4a63]">{service.navLabel}</p>
                    <h3 className="mt-2 text-xl font-bold text-[#0d2d44]">{service.name}</h3>
                    <p className="mt-3 text-sm text-[#5c6875]">{service.shortDescription}</p>
                    <span className="mt-5 inline-flex text-sm font-semibold text-[#0d2d44]">Explore hub</span>
                  </Link>
                );
              })}
            </div>
          </div>
        </section>

        <section className="iris-section iris-section-muted">
          <div className="iris-container">
            <h2 className="iris-title">Canadian Location Index</h2>
            <p className="iris-subtitle">Province and city clusters for high-intent emergency searchers.</p>
            <div className="mt-8 grid gap-6 md:grid-cols-2 xl:grid-cols-4">
              {states.map((state) => {
                const stateCities = stateToCities.get(state.slug)?.slice(0, HOMEPAGE_CITIES_PER_STATE) ?? [];
                return (
                  <div key={state.slug} className="iris-card iris-card-pad">
                    <h3 className="text-xl font-bold text-[#0d2d44]">{state.name}</h3>
                    <ul className="mt-4 space-y-2">
                      {stateCities.map((city) => (
                        <li key={city.citySlug}>
                          <Link
                            className="iris-link text-sm"
                            href={`/${state.slug}/${city.citySlug}/water-damage`}
                          >
                            {serviceLocationKeyword(primaryService.name, city.cityName)}
                          </Link>
                        </li>
                      ))}
                    </ul>
                  </div>
                );
              })}
            </div>
            <p className="mt-6 text-sm text-[#5c6875]">
              Showing {HOMEPAGE_STATE_LIMIT} provinces/states and up to {HOMEPAGE_CITIES_PER_STATE} cities each for
              faster page delivery.
            </p>
          </div>
        </section>
      </main>
    </div>
  );
}
